$repo = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$prNum = 42
$timeout = 600
$interval = 30
$elapsed = 0

while ($elapsed -lt $timeout) {
    # Strategy A
    $reviews = gh api "/repos/$repo/pulls/$prNum/reviews" --jq '.[] | select(.body | test("Copilot.s findings"; "i")) | {id: .id, body: .body, user: .user.login}' 2>$null

    # Strategy B
    if (-not $reviews) {
        $reviews = gh api "/repos/$repo/pulls/$prNum/reviews" --jq '.[] | select(.body | test("Pull request overview"; "i")) | {id: .id, body: .body, user: .user.login}' 2>$null
    }

    # Strategy C
    if (-not $reviews) {
        $reviews = gh api "/repos/$repo/pulls/$prNum/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | {id: .id, body: .body, user: .user.login}' 2>$null
    }

    # Strategy D
    if (-not $reviews) {
        $copilotComments = gh api "/repos/$repo/pulls/$prNum/comments" --jq '.[] | select(.user.login == "Copilot") | {id: .id, body: .body}' 2>$null
        if ($copilotComments) { $reviews = $copilotComments }
    }

    if ($reviews) {
        Write-Output "FOUND COPILOT REVIEW at ${elapsed}s:"
        Write-Output $reviews
        break
    }

    Write-Output "Waiting... ${elapsed}s elapsed"
    Start-Sleep -Seconds $interval
    $elapsed += $interval
}

if (-not $reviews) {
    Write-Output "TIMEOUT: No Copilot review found after ${timeout}s"
}

